var body = $input.first().json.body || $input.first().json;

if (!body.tenantId || !body.nom || !body.sujet) {
  throw new Error('tenantId, nom, sujet are required');
}

function esc(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }
function escUuid(v) { return v == null ? 'NULL' : esc(v) + '::uuid'; }

var status = body.scheduledAt ? 'planifiee' : 'brouillon';

var query = "INSERT INTO email_campaigns (tenant_id, nom, sujet, template_id, list_id, contenu_html, contenu_text, expediteur_nom, expediteur_email, status, scheduled_at) VALUES ("
  + escUuid(body.tenantId) + ", "
  + esc(body.nom) + ", "
  + esc(body.sujet) + ", "
  + escUuid(body.templateId) + ", "
  + escUuid(body.listId) + ", "
  + esc(body.contenuHtml || '<p></p>') + ", "
  + esc(body.contenuText) + ", "
  + esc(body.expediteurNom || 'Newsletter') + ", "
  + esc(body.expediteurEmail || 'noreply@example.com') + ", "
  + esc(status) + ", "
  + (body.scheduledAt ? esc(body.scheduledAt) + '::timestamptz' : 'NULL') + ")"
  + ' RETURNING id, tenant_id AS "tenantId", nom, sujet, template_id AS "templateId", list_id AS "listId", contenu_html AS "contenuHtml", contenu_text AS "contenuText", expediteur_nom AS "expediteurNom", expediteur_email AS "expediteurEmail", status, scheduled_at AS "scheduledAt", sent_at AS "sentAt", total_envoyes AS "totalEnvoyes", total_ouverts AS "totalOuverts", total_cliques AS "totalCliques", total_bounces AS "totalBounces", total_desabonnes AS "totalDesabonnes", created_at AS "createdAt", updated_at AS "updatedAt"';

return [{ json: { tenantId: body.tenantId, query: query } }];

var items = $('05. Insert Query').all();
var campaign = items[0] ? items[0].json : {};
return [{ json: { campaign: campaign } }];
